#!/usr/bin/env bash
# Generated by bun-bench Harbor export adapter. Oracle reference solution.
# Overwrites the starter source under /app with the bun-bench reference.
set -euo pipefail

mkdir -p /app/src
cat > /app/src/server.ts <<'BUN_BENCH_SOLUTION_EOF'
import { randomUUID } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);

type Order = {
  id: string;
  reference: string;
  item: string;
  qty: number;
  status: "created";
};
type StoredResponse = { fingerprint: string; order: Order };

const orders = new Map<string, Order>();
// Per-key record of the first completed create.
const byKey = new Map<string, StoredResponse>();
// Business-level uniqueness index: reference -> order id.
const byReference = new Map<string, string>();

function fingerprint(reference: string, item: string, qty: number): string {
  return JSON.stringify({ reference, item, qty });
}

function orderBody(o: Order) {
  return { id: o.id, reference: o.reference, item: o.item, qty: o.qty, status: o.status };
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const segments = url.pathname.split("/").filter(Boolean);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/orders") {
      const key = request.headers.get("idempotency-key");
      if (key === null || key.trim() === "") {
        return Response.json({ error: "missing_idempotency_key" }, { status: 400 });
      }

      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      const reference = record?.reference;
      const item = record?.item;
      const qty = record?.qty;
      if (
        typeof reference !== "string" ||
        typeof item !== "string" ||
        typeof qty !== "number" ||
        !Number.isInteger(qty) ||
        qty <= 0
      ) {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }

      const fp = fingerprint(reference, item, qty);

      // Idempotency key takes precedence: a known key is always a replay or a
      // key-reuse conflict, never a duplicate_reference.
      const existing = byKey.get(key);
      if (existing) {
        if (existing.fingerprint !== fp) {
          return Response.json({ error: "idempotency_key_reuse" }, { status: 409 });
        }
        return Response.json(orderBody(existing.order), {
          status: 201,
          headers: { "Idempotency-Replayed": "true" },
        });
      }

      // New key: enforce business-level uniqueness on the reference.
      if (byReference.has(reference)) {
        return Response.json({ error: "duplicate_reference" }, { status: 409 });
      }

      const order: Order = {
        id: randomUUID(),
        reference,
        item,
        qty,
        status: "created",
      };
      orders.set(order.id, order);
      byKey.set(key, { fingerprint: fp, order });
      byReference.set(reference, order.id);
      return Response.json(orderBody(order), { status: 201 });
    }

    if (segments.length === 2 && segments[0] === "orders" && request.method === "GET") {
      const order = orders.get(segments[1]);
      if (!order) return Response.json({ error: "not_found" }, { status: 404 });
      return Response.json(orderBody(order), { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`dedup-conflict reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
